package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testToString() throws Exception {
    // Directly use LineItem.class instead of Class.forName to avoid ClassNotFoundException
    Class<?> lineItemClass = LineItem.class;
    var constructor = lineItemClass.getConstructor(String.class, int.class, long.class, String.class);
    Object item = constructor.newInstance("apple", 5, 123456789L, "USD");

    String expected = "(item: apple, qty: 5, price: 123.46 USD)";
    String actual = item.toString();

    assertEquals(expected, actual);
  }
}
